// src/domain/entities/Order.ts
export class Order {
  private readonly id: string;
  private items: OrderItem[];
  private status: OrderStatus;
  private readonly events: DomainEvent[] = [];

  private constructor(id: string, items: OrderItem[], status: OrderStatus) {
    if (items.length === 0) throw new Error('Order must have at least one item');
    this.id = id;
    this.items = items;
    this.status = status;
  }

  static create(id: string, items: OrderItem[]): Order {
    return new Order(id, items, OrderStatus.PENDING);
  }

  static reconstitute(id: string, items: OrderItem[], status: OrderStatus): Order {
    return new Order(id, items, status);
  }

  get total(): Money {
    return this.items.reduce((sum, item) => sum.add(item.subtotal), Money.zero());
  }

  place(): void {
    if (this.status !== OrderStatus.PENDING) throw new Error('Can only place pending orders');
    this.status = OrderStatus.PLACED;
    this.events.push(new OrderPlaced(this.id, this.total));
  }

  cancel(): void {
    if (this.status === OrderStatus.SHIPPED) throw new Error('Cannot cancel shipped orders');
    this.status = OrderStatus.CANCELLED;
  }

  pullEvents(): DomainEvent[] {
    const events = [...this.events];
    this.events.length = 0;
    return events;
  }
}

// src/application/use-cases/PlaceOrder.ts
export class PlaceOrder {
  constructor(
    private readonly orderRepository: IOrderRepository,
    private readonly paymentService: IPaymentService,
    private readonly inventoryService: IInventoryService
  ) {}

  async execute(request: PlaceOrderRequest): Promise<OrderResponse> {
    await this.inventoryService.reserveItems(request.items);
    const order = Order.create(
      crypto.randomUUID(),
      request.items.map(i => new OrderItem(i.productId, i.quantity, i.price))
    );
    await this.paymentService.charge(request.customerId, order.total);
    order.place();
    await this.orderRepository.save(order);
    return OrderResponse.fromOrder(order);
  }
}

// BAD: entity is a data bag
class Order { customerId: string; items: any[]; status: string; }

// BAD: business logic in service
class OrderService {
  place(order: Order) {
    if (order.status !== 'PENDING') throw new Error('...');
    order.status = 'PLACED'; // direct mutation, no event
  }
}
